"use strict";(self.webpackChunktorabian_github_io=self.webpackChunktorabian_github_io||[]).push([[8110],{5054:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>h,frontMatter:()=>o,metadata:()=>s,toc:()=>c});const s=JSON.parse('{"type":"mdx","permalink":"/insight/user-role-tenant-control-in-projects","source":"@site/src/pages/insight/user-role-tenant-control-in-projects.mdx","title":"User, Role, and Tenant Management in Modern Applications","description":"Unless you are building a very simple application with no authentication\u2014or a static website without user accounts\u2014most systems require some form of user management.","frontMatter":{},"unlisted":false}');var i=n(4848),a=n(8453);const o={},r="User, Role, and Tenant Management in Modern Applications",l={},c=[{value:"Evolving Alternatives for Identity Management",id:"evolving-alternatives-for-identity-management",level:2},{value:"The Real Issue with Third-Party Identity Services",id:"the-real-issue-with-third-party-identity-services",level:2},{value:"Solution",id:"solution",level:2},{value:"Understanding Real User Management Requirements",id:"understanding-real-user-management-requirements",level:2},{value:"User, Passport, Role, Workspace, and Permissions",id:"user-passport-role-workspace-and-permissions",level:2},{value:"User entity (table)",id:"user-entity-table",level:3},{value:"Passport entity (table)",id:"passport-entity-table",level:3},{value:"Role entity",id:"role-entity",level:3},{value:"Workspace",id:"workspace",level:3},{value:"Permission table",id:"permission-table",level:3},{value:"Interface Strucutre",id:"interface-strucutre",level:2},{value:"Discovering the available passport methods.",id:"discovering-the-available-passport-methods",level:3},{value:"Conclusion",id:"conclusion",level:2}];function d(e){const t={code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"user-role-and-tenant-management-in-modern-applications",children:"User, Role, and Tenant Management in Modern Applications"})}),"\n",(0,i.jsx)(t.p,{children:"Unless you are building a very simple application with no authentication\u2014or a static website without user accounts\u2014most systems require some form of user management.\nIn its simplest form, user management involves allowing users to register with an email address, optionally confirm that email, and gain access to the system. This model was sufficient in the early days of the web, particularly in the late 1990s and even into the 2005\u20132010 era, when many applications operated with minimal identity requirements.\nHowever, expectations have evolved significantly."}),"\n",(0,i.jsx)(t.p,{children:"Today, users interact with applications across multiple devices\u2014mobile apps, web platforms, and integrated ecosystems. Identity management has become far more complex. A single account (such as a Google account) can span multiple applications, devices, roles, and workspaces, all tied to the same individual.\nAt this scale, a dedicated identity system becomes necessary. These systems must handle numerous edge cases and typically require specialized teams to build, maintain, audit, and support them. They often provide SDKs for various platforms (iOS, Android, web) and include extensive feature sets.\nThe challenge is that many of these features are no longer optional\u2014even for relatively simple businesses. For example, an online ticketing platform may still need to support email and phone verification, password recovery, and multi-factor authentication, despite having a straightforward business model."}),"\n",(0,i.jsx)(t.p,{children:"In Software-as-a-Service (SaaS) environments, the complexity increases further. Data is no longer owned by individual users but by shared entities often referred to as \u201cworkspaces\u201d or \u201ctenants.\u201d A tenant represents a group of users operating within a shared context, typically isolated from other tenants within the same system.\nThis introduces a new set of requirements: role-based access control, user invitations, permission management, and fine-grained data visibility. These must integrate seamlessly with authentication flows such as OTP, TOTP, and other modern security mechanisms.\nAs a result, user, role, and tenant management has evolved from a simple feature into a core architectural concern in modern software systems."}),"\n",(0,i.jsx)(t.h2,{id:"evolving-alternatives-for-identity-management",children:"Evolving Alternatives for Identity Management"}),"\n",(0,i.jsx)(t.p,{children:"Over the past decades, several solutions have emerged to simplify and standardize identity management across applications.\nOne of the more accessible options is Firebase, which provides authentication services as part of a broader backend platform. It is relatively easy to integrate and works well for smaller applications or projects that don\u2019t require deep customization, though its flexibility can be limited for more complex use cases."}),"\n",(0,i.jsx)(t.p,{children:"On the other end of the spectrum, Keycloak offers a powerful, open-source solution for centralized authentication and authorization. It supports advanced features such as single sign-on (SSO), identity brokering, and fine-grained access control, making it suitable for larger systems with more demanding requirements."}),"\n",(0,i.jsx)(t.p,{children:"In addition to these general-purpose solutions, more specialized approaches have emerged. For example, Fireback ABAC\u2014built using Go within the Fireback ecosystem\u2014focuses on attribute-based access control. This approach allows for more flexible and expressive permission systems, particularly in SaaS environments where roles alone are often insufficient.\nEach of these solutions reflects a different trade-off between simplicity, flexibility, and control. Choosing the right one depends less on current needs and more on how complex the system is expected to become over time\u2014a decision that tends to have long-term architectural consequences."}),"\n",(0,i.jsx)(t.h2,{id:"the-real-issue-with-third-party-identity-services",children:"The Real Issue with Third-Party Identity Services"}),"\n",(0,i.jsx)(t.p,{children:"In practice, third-party identity solutions often introduce more complexity than they remove\u2014especially as a system evolves."}),"\n",(0,i.jsx)(t.p,{children:"From experience building libraries, solutions that are embedded directly within the project\u2019s codebase tend to be significantly easier to work with. They offer full control, predictable behavior, and faster iteration. In contrast, external identity services often require extensive configuration to align with specific business needs."}),"\n",(0,i.jsx)(t.p,{children:"User identity management is rarely generic. It depends heavily on factors such as the type of business, regulatory requirements, and the geographical location of both the company and its users. As a result, adapting a shared, third-party solution to fit these constraints often leads to continuous adjustments and workarounds, making long-term maintenance harder rather than easier."}),"\n",(0,i.jsx)(t.p,{children:"Another practical challenge is user experience. Seamless integration of authentication flows is difficult when relying on external systems. Many third-party providers require redirecting users to external domains for login and then returning them to the application. On the web, this typically involves subdomains; on mobile, it often relies on embedded web views."}),"\n",(0,i.jsx)(t.p,{children:"While functional, this approach can feel disjointed and limits control over the user experience. In contrast, implementing authentication directly within the application allows for tighter integration, better consistency, and more flexibility in tailoring the flow to the product\u2019s needs."}),"\n",(0,i.jsx)(t.p,{children:"In the long run, the trade-off becomes clear: third-party services may accelerate initial development, but they often introduce constraints that become increasingly costly as the product grows."}),"\n",(0,i.jsx)(t.p,{children:"In order to also seamlessly integrate authentication flow into the app, those screens\nare required to be created instead of redirecting user to a different software to authenticate\nand send them back, which is done via subdomain on web or webview is mobile applications."}),"\n",(0,i.jsx)(t.h2,{id:"solution",children:"Solution"}),"\n",(0,i.jsx)(t.p,{children:"In the long run, building your own identity management system is not optional\u2014it\u2019s inevitable.\nAt the early stages of a project, investing in a custom solution may seem unnecessary. Third-party services are attractive because they reduce initial development time and allow you to move faster. However, this advantage is temporary.\nAs your application grows, identity management becomes deeply tied to your core business logic. You will want full control over every aspect: backend behavior, frontend experience, and the entire user journey\u2014from registration to authentication and beyond.\nAt that point, external solutions start to feel restrictive. Custom flows, edge cases, and business-specific rules become harder to implement cleanly. What once saved time begins to slow you down.\nBuilding your own system gives you control where it actually matters:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"You define authentication flows without compromise"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"You design user experiences without redirections or external dependencies"}),"\n"]}),"\n",(0,i.jsxs)(t.li,{children:["\n",(0,i.jsx)(t.p,{children:"You adapt quickly to new requirements without fighting a third-party abstraction"}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"A more realistic strategy is not \u201cbuild everything from day one,\u201d but rather:\nstart simple, and gradually take ownership of identity as your system proves its value.\nBecause if your product succeeds, identity management stops being a feature\u2014and becomes infrastructure."}),"\n",(0,i.jsx)(t.h2,{id:"understanding-real-user-management-requirements",children:"Understanding Real User Management Requirements"}),"\n",(0,i.jsx)(t.p,{children:"Even if you use a third-party solution, you need to understand how user management actually works."}),"\n",(0,i.jsx)(t.p,{children:"If you don\u2019t, you\u2019ll likely underestimate the complexity and face painful refactoring later\u2014especially at the database level, where changes are costly and risky."}),"\n",(0,i.jsx)(t.p,{children:"User management goes beyond authentication. It affects data ownership, access control, and how your system evolves. Ignoring this early creates long-term limitations."}),"\n",(0,i.jsx)(t.p,{children:"In the following sections, these concepts are explained using the Fireback ABAC module\u2014but the requirements themselves apply to any serious application."}),"\n",(0,i.jsx)(t.h2,{id:"user-passport-role-workspace-and-permissions",children:"User, Passport, Role, Workspace, and Permissions"}),"\n",(0,i.jsx)(t.p,{children:"From a database perspective, a reliable long-term structure requires a few fundamental tables."}),"\n",(0,i.jsx)(t.h3,{id:"user-entity-table",children:"User entity (table)"}),"\n",(0,i.jsxs)(t.p,{children:["A ",(0,i.jsx)(t.strong,{children:"User"})," is an entity that represents an actor in the system, not necessarily a person.\nA common mistake is assigning first name and last name to this entity in database design.\nIn such scenarios, you cannot distinguish between a real person, a bot, or a service worker\nthat also operates within the system. A person can be associated with a user in a many-to-one\nrelationship. This means that, in theory, a person can have multiple users in the system,\nalthough in most cases this relationship is one-to-one."]}),"\n",(0,i.jsx)(t.h3,{id:"passport-entity-table",children:"Passport entity (table)"}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Passport"})," is an entity that represents how a user can authenticate within the system."]}),"\n",(0,i.jsxs)(t.p,{children:["In many systems, the ",(0,i.jsx)(t.code,{children:"user"})," table contains fields like ",(0,i.jsx)(t.code,{children:"username"})," and ",(0,i.jsx)(t.code,{children:"email"}),". This approach quickly becomes limiting when adding new authentication methods such as OAuth providers, SMS-based login, or other mechanisms."]}),"\n",(0,i.jsx)(t.p,{children:"Instead, a user can have none, one, or multiple passports. For example:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"A user may authenticate without a passport, such as a guest user where the system assigns a temporary identity upon visiting the website."}),"\n",(0,i.jsx)(t.li,{children:"A user may have multiple email-based passports, allowing authentication with different email addresses under the same account."}),"\n",(0,i.jsx)(t.li,{children:"A user may add a phone number and use it as their primary authentication method."}),"\n",(0,i.jsx)(t.li,{children:"A user may link a Facebook account and log in through it."}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"With a dedicated passport table, all authentication methods are tracked in a unified way. When a new authentication method is introduced, it can be added as a new record instead of requiring schema changes or migrations."}),"\n",(0,i.jsx)(t.p,{children:"This design also enables dynamic configuration of authentication strategies. For example, SMS login can be enabled only in specific countries, or the system can be restricted to Google-only authentication without requiring structural changes in the future."}),"\n",(0,i.jsx)(t.h3,{id:"role-entity",children:"Role entity"}),"\n",(0,i.jsx)(t.p,{children:"Role entity has no direct connection to the user. Roles are defined in the system by administration. This can also be nested. For example, a root admin defines a set of available roles, while a workspace owner can define custom roles within their own organization."}),"\n",(0,i.jsxs)(t.p,{children:["Each role can contain zero to many permissions. Each permission is represented as a string describing an allowed action. These can also be wildcards, such as ",(0,i.jsx)(t.code,{children:"user/*"}),", meaning all actions under the user service are permitted if enabled for that role."]}),"\n",(0,i.jsxs)(t.p,{children:['Having a role entity is very important. It can be used to limit workspace types. A further discussion is needed here, but for now assume a web application with "Student" and "Teacher" sections. In this case, the system may have three workspace types: ',(0,i.jsx)(t.code,{children:"root"}),", ",(0,i.jsx)(t.code,{children:"teacher"}),", and ",(0,i.jsx)(t.code,{children:"student"}),". Each workspace is restricted using roles, and further access levels are defined from there."]}),"\n",(0,i.jsx)(t.p,{children:"Therefore, a role table is required to store sets of permissions, along with a linking table for capabilities. Capabilities themselves are not stored directly in the database, which allows adding or removing them later without major changes to the application, even for features that did not exist at the initial stage."}),"\n",(0,i.jsx)(t.h3,{id:"workspace",children:"Workspace"}),"\n",(0,i.jsxs)(t.p,{children:["Workspace is the heart of this whole design. It links users into workspaces and defines the roles they can have. This is achieved through a few tables; the most important are ",(0,i.jsx)(t.strong,{children:"User Workspace"})," and ",(0,i.jsx)(t.strong,{children:"Workspace Role"}),"."]}),"\n",(0,i.jsxs)(t.p,{children:["Using this combination, we control who belongs to a workspace and, more importantly, which role they have within it. In this setup, ",(0,i.jsx)(t.em,{children:"Ali"})," can belong to both Google and Microsoft workspaces. In Google, he may have a developer role, while in Microsoft he may be a consultant."]}),"\n",(0,i.jsx)(t.p,{children:"Adding a user to a workspace requires a record in both tables. If a user belongs to a workspace but does not have a role, they can only perform actions that do not require permissions, which is obviously quite rare."}),"\n",(0,i.jsx)(t.p,{children:"The same user can also have multiple roles within a workspace. A common example is a financial application, where the same person can be both CEO and accountant at the same time. However, accepting an invoice is only possible through the accountant role, even if the person is CEO and therefore cannot perform that action through the CEO role alone."}),"\n",(0,i.jsx)(t.h3,{id:"permission-table",children:"Permission table"}),"\n",(0,i.jsx)(t.p,{children:"Another important table is the permissions table, as mentioned earlier. This table only contains permission strings and a label, which can be translated into different languages."}),"\n",(0,i.jsx)(t.p,{children:"In Fireback, you can define as many permissions as needed and manage users based on whether they have those permissions."}),"\n",(0,i.jsx)(t.h2,{id:"interface-strucutre",children:"Interface Strucutre"}),"\n",(0,i.jsx)(t.p,{children:"All we have discussed so far is how to organize the database to provide as much flexibility as possible. Now let\u2019s dive into an actual implementation of this structure."}),"\n",(0,i.jsx)(t.p,{children:"When you download the Fireback project or install it as a single binary, all the topics covered in this article are already implemented. In the following sections, we will go through these methods and explain them."}),"\n",(0,i.jsx)(t.h3,{id:"discovering-the-available-passport-methods",children:"Discovering the available passport methods."}),"\n",(0,i.jsxs)(t.p,{children:["Before a user begins authentication (assuming they are not authenticated or are using an anonymous guest mode), the system needs to retrieve information through a ",(0,i.jsx)(t.code,{children:"check passport"})," endpoint."]}),"\n",(0,i.jsx)(t.p,{children:"This endpoint is publicly available and can be cached if there are no frequent changes in the system configuration."}),"\n",(0,i.jsx)(t.p,{children:"Below is an example of how it can be accessed via CLI and the expected response."}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-bash",children:"$ fireback passport check-passport-methods\n"})}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-json",children:'{\n  "email": true,\n  "phone": true,\n  "google": false,\n  "facebook": false,\n  "googleOAuthClientKey": "",\n  "facebookAppId": "",\n  "enabledRecaptcha2": false,\n  "recaptcha2ClientKey": ""\n}\n'})}),"\n",(0,i.jsxs)(t.p,{children:["As you can see, there are flags returned that allow the front-end (web or mobile app) to understand what is available in the system, so the interface can be adjusted accordingly. For example, if ",(0,i.jsx)(t.code,{children:"facebook"})," is true, a \u201cLogin with Facebook\u201d button can be shown."]}),"\n",(0,i.jsx)(t.p,{children:"The content of this response can vary depending on the user. For instance, in Germany you may allow phone login, while Facebook login is only available in the United States for certain reasons."}),"\n",(0,i.jsx)(t.p,{children:"Fireback already provides basic options for this, but in most cases you will need to extend it."}),"\n",(0,i.jsx)(t.p,{children:"From this point, the interface is rendered and presented to the user."}),"\n",(0,i.jsx)(t.h2,{id:"conclusion",children:"Conclusion"}),"\n",(0,i.jsx)(t.p,{children:"As shown throughout this article, user management is not straightforward. However, it is also not overly complex. The goal here is simply to demonstrate the scale and importance of such systems."})]})}function h(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>o,x:()=>r});var s=n(6540);const i={},a=s.createContext(i);function o(e){const t=s.useContext(a);return s.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),s.createElement(a.Provider,{value:t},e.children)}}}]);